const body = $input.first().json.body;
const message = body.message || body.edited_message;
if (!message) { return []; }
const chat_id = message.chat.id;
const from_id = message.from.id;
const from_name = message.from.first_name || 'Sem nome';
const text = message.text || '';
const message_id = message.message_id;
if (!text || text.trim() === '') { return []; }
return [{ json: { chat_id, from_id, from_name, text, message_id } }];

const agora = new Date();
const hora = agora.getHours();
const diaSemana = agora.getDay();
const dentroHorario = diaSemana >= 1 && diaSemana <= 6 && hora >= 8 && hora < 18;
return [{ json: { ...$input.first().json, dentroHorario } }];

const chat_id = $input.first().json.chat_id;
const from_name = $input.first().json.from_name;
const texto = `Ola, ${from_name}!

A Dra. Vanessa esta fora do horario de atendimento no momento.

Se for uma urgencia, procure um servico veterinario 24 horas mais proximo.

Nos demais casos, ela retornara sua mensagem assim que possivel.`;
return [{ json: { chat_id, texto } }];

const eventos = $input.all();
const temEvento = eventos.length > 0 && eventos[0].json.id;
const chat_id = $('Extrai mensagem').first().json.chat_id;
const from_id = $('Extrai mensagem').first().json.from_id;
const from_name = $('Extrai mensagem').first().json.from_name;
const text = $('Extrai mensagem').first().json.text;
return [{ json: { chat_id, from_id, from_name, text, vanessaOcupada: temEvento } }];

const caso = $('Busca caso no Neon').all();
const temCaso = caso.length > 0 && caso[0].json.caso_id;
const estado = $('Avalia estado Vanessa').first().json;
const historicoRows = $('Busca historico').all();

let historico = [];
try {
  if (historicoRows.length > 0 && historicoRows[0].json.historico) {
    historico = JSON.parse(historicoRows[0].json.historico);
  }
} catch(e) { historico = []; }

historico.push({ role: 'user', content: estado.text });

let situacao;
if (!estado.vanessaOcupada) {
  situacao = 'livre';
} else if (temCaso) {
  situacao = 'ocupada_caso_antigo';
} else {
  situacao = 'ocupada_caso_novo';
}

const animal_nome = temCaso ? caso[0].json.animal_nome : null;
const tutor_nome = temCaso ? caso[0].json.tutor_nome : estado.from_name;

return [{ json: { chat_id: estado.chat_id, from_name: estado.from_name, text: estado.text, situacao, animal_nome, tutor_nome, historico } }];

const dados = $input.first().json;
const chat_id = dados.chat_id;
const tutor_nome = dados.tutor_nome;
const animal_nome = dados.animal_nome;
const situacao = dados.situacao;
let texto;
if (situacao === 'livre') {
  texto = `Ola, ${tutor_nome}!\n\nA Dra. Vanessa esta concluindo um atendimento e retornara sua mensagem em breve.\n\nFique a vontade para relatar o que esta acontecendo que ela lera assim que puder.`;
} else {
  texto = `Ola, ${tutor_nome}!\n\nA Dra. Vanessa esta em atendimento no momento e retornara sua mensagem em breve.\n\nFique a vontade para relatar o que esta acontecendo com ${animal_nome || 'seu animal'} que ela lera assim que puder.`;
}
return [{ json: { chat_id, texto, historico: dados.historico } }];

